136.                     var fileExtension = Path.GetExtension(teachingMaterialImage.FileName).ToLower();
137.                     if (!allowedExtensions.Contains(fileExtension))
138.                     {
139.                         ModelState.AddModelError("teachingMaterialImage", "Please upload a valid image file (jpg, jpeg, png, gif, bmp).");
140.                         ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name", course.DepartmentID);
141.                         return View(course);
142.                     }
143.                     if (teachingMaterialImage.Length > 5 * 1024 * 1024)
144.                     {
145.                         ModelState.AddModelError("teachingMaterialImage", "File size must be less than 5MB.");
146.                         ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name", course.DepartmentID);
147.                         return View(course);
148.                     }
149.                     try
150.                     {
151.                         var uploadsPath = Path.Combine(_env.WebRootPath ?? _env.ContentRootPath, "Uploads", "TeachingMaterials");
152.                         Directory.CreateDirectory(uploadsPath);
153.                         var fileName = $"course_{course.CourseID}_{Guid.NewGuid()}{fileExtension}";
154.                         var filePath = Path.Combine(uploadsPath, fileName);
155. 
156.                         if (!string.IsNullOrEmpty(course.TeachingMaterialImagePath))
157.                         {
158.                             var oldFilePath = Path.Combine(_env.WebRootPath ?? _env.ContentRootPath, course.TeachingMaterialImagePath.TrimStart('/').Replace('/', Path.DirectorySeparatorChar));
159.                             if (System.IO.File.Exists(oldFilePath))
160.                             {
161.                                 try { System.IO.File.Delete(oldFilePath); } catch { }
162.                             }
163.                         }
164.                         using (var stream = System.IO.File.Create(filePath))
165.                         {
166.                             teachingMaterialImage.CopyTo(stream);
167.                         }
168.                         course.TeachingMaterialImagePath = $"/Uploads/TeachingMaterials/{fileName}";
169.                     }
170.                     catch (Exception ex)
171.                     {
172.                         _logger.LogError(ex, "Error uploading file");
173.                         ModelState.AddModelError("teachingMaterialImage", "Error uploading file: " + ex.Message);
174.                         ViewBag.DepartmentID = new SelectList(db.Departments, "DepartmentID", "Name", course.DepartmentID);
