1. using System;
2. using System.Collections.Concurrent;
3. using ContosoUniversity.Models;
4. 
5. namespace ContosoUniversity.Services
6. {
7.     public class NotificationService : IDisposable
8.     {
9.         // Static shared queue across application instances (simple in-memory alternative to MSMQ)
10.         private static readonly ConcurrentQueue<Notification> _queue = new();
11.         private static readonly int _maxQueueLength = 500; // basic cap to prevent unbounded growth
12. 
13.         public NotificationService()
14.         {
14.             // No initialization required for in-memory queue
15.         }
16. 
17.         public void SendNotification(string entityType, string entityId, EntityOperation operation, string userName = null)
18.         {
18.             SendNotification(entityType, entityId, null, operation, userName);
19.         }
20. 
21.         public void SendNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation, string userName = null)
22.         {
22.             try
23.             {
24.                 var notification = new Notification
24.                 {
25.                     EntityType = entityType,
26.                     EntityId = entityId,
26.                     Operation = operation.ToString(),
27.                     Message = GenerateMessage(entityType, entityId, entityDisplayName, operation),
27.                     CreatedAt = DateTime.Now,
28.                     CreatedBy = userName ?? "System",
29.                     IsRead = false
30.                 };
31. 
32.                 _queue.Enqueue(notification);
32. 
33.                 // Enforce max queue length (best-effort)
34.                 while (_queue.Count > _maxQueueLength && _queue.TryDequeue(out _)) { }
34.             }
35.             catch (Exception ex)
35.             {
36.                 System.Diagnostics.Debug.WriteLine($"Failed to enqueue notification: {ex.Message}");
36.             }
37.         }
37. 
38.         public Notification ReceiveNotification()
38.         {
39.             try
39.             {
40.                 return _queue.TryDequeue(out var notification) ? notification : null;
40.             }
41.             catch (Exception ex)
41.             {
42.                 System.Diagnostics.Debug.WriteLine($"Failed to receive notification: {ex.Message}");
42.                 return null;
43.             }
44.         }
44. 
45.         public void MarkAsRead(int notificationId)
45.         {
46.             // No-op for in-memory implementation (persistence not implemented)
47.         }
47. 
48.         private string GenerateMessage(string entityType, string entityId, string entityDisplayName, EntityOperation operation)
48.         {
49.             var displayText = !string.IsNullOrWhiteSpace(entityDisplayName)
49.                 ? $"{entityType} '{entityDisplayName}'"
50.                 : $"{entityType} (ID: {entityId})";
50. 
51.             return operation switch
51.             {
52.                 EntityOperation.CREATE => $"New {displayText} has been created",
52.                 EntityOperation.UPDATE => $"{displayText} has been updated",
53.                 EntityOperation.DELETE => $"{displayText} has been deleted",
54.                 _ => $"{displayText} operation: {operation}"
54.             };
55.         }
55. 
56.         public void Dispose()
56.         {
57.             // Nothing to dispose for in-memory queue
57.         }
58.     }
59. }
