6. {
7.     public class PaginatedList<T> : List<T>
8.     {
9.         public int PageIndex { get; private set; }
10.         public int TotalPages { get; private set; }
11. 
12.         public PaginatedList(List<T> items, int count, int pageIndex, int pageSize)
13.         {
13.             PageIndex = pageIndex;
14.             TotalPages = (int)Math.Ceiling(count / (double)pageSize);
14. 
15.             this.AddRange(items);
15.         }
16. 
17.         public bool HasPreviousPage => PageIndex > 1;
17. 
18.         public bool HasNextPage => PageIndex < TotalPages;
18. 
19.         public static PaginatedList<T> Create(IQueryable<T> source, int pageIndex, int pageSize)
19.         {
20.             var count = source.Count();
20.             var items = source.Skip((pageIndex - 1) * pageSize).Take(pageSize).ToList();
21.             return new PaginatedList<T>(items, count, pageIndex, pageSize);
21.         }
22.     }
