using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateContext();
            TestHelpers.SeedStudents(_context);
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // -------- Index --------

        [Fact]
        public void Index_NoParams_ReturnsViewWithStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAsc()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDesc()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal("Anand", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Alexander", model[2].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAsc()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal("Alexander", model[0].LastName); // 2010
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Equal("Anand", model[0].LastName); // 2013
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
            Assert.Equal("Carson", model[0].FirstMidName);
        }

        [Fact]
        public void Index_SearchStringResetsPage()
        {
            var result = _controller.Index(null, null, "A", 3) as ViewResult;
            // When searchString is not null, page is reset to 1
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearch_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);

            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagSortParms()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_DateSort_DateSortParmTogglesToDesc()
        {
            _controller.Index("Date", null, null, null);

            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        // -------- Details --------

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Need enrollments loaded - add them
            _context.Courses.Add(new Course { CourseID = 999, Title = "Test", Credits = 3, DepartmentID = 0 });
            _context.Enrollments.Add(new Enrollment { EnrollmentID = 99, StudentID = 1, CourseID = 999, Grade = Grade.A });
            _context.SaveChanges();

            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        // -------- Create GET --------

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        // -------- Create POST --------

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, _context.Students.Count());
        }

        [Fact]
        public void Create_Post_DefaultDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Bad",
                FirstMidName = "Student",
