using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;
        private readonly string _tempRoot;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateContext();
            TestHelpers.SeedCourses(_context);
            _envMock = new Mock<IWebHostEnvironment>();
            _loggerMock = new Mock<ILogger<CoursesController>>();
            _tempRoot = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempRoot);
            _envMock.Setup(e => e.WebRootPath).Returns(_tempRoot);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempRoot);
            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempRoot))
                Directory.Delete(_tempRoot, recursive: true);
        }

        // -------- Index --------

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var courses = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(3, courses.Count);
        }

        // -------- Details --------

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsView()
        {
            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        // -------- Create GET --------

        [Fact]
        public void Create_Get_ReturnsViewWithNewCourse()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // -------- Create POST --------

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.NotNull(_context.Courses.Find(9999));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 5555, Credits = 3, DepartmentID = 1 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesFile()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", 1024);

            var result = _controller.Create(course, fileMock.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var saved = _context.Courses.Find(8888);
            Assert.NotNull(saved);
            Assert.NotNull(saved.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_InvalidExtension_ReturnsViewWithError()
        {
            var course = new Course { CourseID = 7777, Title = "Bad Ext", Credits = 3, DepartmentID = 1 };
            var fileMock = CreateMockFormFile("test.txt", 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = new Course { CourseID = 6666, Title = "Too Large", Credits = 3, DepartmentID = 1 };
            var fileMock = CreateMockFormFile("test.jpg", 6 * 1024 * 1024);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // -------- Edit GET --------

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsView()
        {
            var result = _controller.Edit(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        // -------- Edit POST --------

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            // Detach tracked entity
            var tracked = _context.Courses.Local.FirstOrDefault(c => c.CourseID == 1050);
            if (tracked != null)
                _context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course
            {
                CourseID = 1050,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, Credits = 3, DepartmentID = 1 };

            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_WithValidImage_UpdatesPath()
        {
            var tracked = _context.Courses.Local.FirstOrDefault(c => c.CourseID == 1050);
            if (tracked != null)
                _context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var fileMock = CreateMockFormFile("newimage.png", 2048);

            var result = _controller.Edit(course, fileMock.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidExtension_ReturnsViewWithError()
        {
            var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var fileMock = CreateMockFormFile("bad.exe", 1024);

            var result = _controller.Edit(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var fileMock = CreateMockFormFile("big.jpg", 6 * 1024 * 1024);

            var result = _controller.Edit(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // -------- Delete GET --------

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsView()
        {
            var result = _controller.Delete(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        // -------- Delete POST --------

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Courses.Find(1050));
        }

        [Fact]
        public void DeleteConfirmed_CourseWithImage_DeletesImageFile()
        {
            // Set up a course with an image path and create the file
            var uploadsPath = Path.Combine(_tempRoot, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsPath);
            var imagePath = Path.Combine(uploadsPath, "test.jpg");
            File.WriteAllText(imagePath, "fake image");

            var course = _context.Courses.Find(1050);
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test.jpg";
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.False(File.Exists(imagePath));
        }

        // -------- Helpers --------

        private static Mock<IFormFile> CreateMockFormFile(string fileName, long length)
        {
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => { });
            return fileMock;
        }
    }
}

