using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestHelpers.CreateContext();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First();

            Assert.Equal("Test", retrieved.FirstMidName);
            Assert.Equal("Student", retrieved.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First();

            Assert.Equal("Test", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddCourseWithDepartment()
        {
            var dept = new Department { Name = "Test", Budget = 1000, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 999, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Include(c => c.Department).First(c => c.CourseID == 999);

            Assert.Equal("Test", retrieved.Department.Name);
        }

        [Fact]
        public void CanAddEnrollment()
        {
            var student = new Student { FirstMidName = "A", LastName = "B", EnrollmentDate = DateTime.Now };
            _context.Students.Add(student);
            _context.SaveChanges();

            var dept = new Department { Name = "D", Budget = 100, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 111, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment { StudentID = student.ID, CourseID = course.CourseID, Grade = Grade.A };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.First();
            Assert.Equal(Grade.A, retrieved.Grade);
        }

        [Fact]
        public void CourseAssignment_CompositeKey_Works()
        {
            var instructor = new Instructor { FirstMidName = "I", LastName = "T", HireDate = DateTime.Now };
            _context.Instructors.Add(instructor);
            var dept = new Department { Name = "D", Budget = 100, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 222, Title = "C2", Credits = 2, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var ca = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments.Find(course.CourseID, instructor.ID);
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void OfficeAssignment_OneToOne_Works()
        {
            var instructor = new Instructor { FirstMidName = "O", LastName = "A", HireDate = DateTime.Now };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var oa = new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 101" };
            _context.OfficeAssignments.Add(oa);
            _context.SaveChanges();

            var retrieved = _context.OfficeAssignments.Find(instructor.ID);
            Assert.Equal("Room 101", retrieved.Location);
        }

        [Fact]
        public void SeedFullData_PopulatesAllEntities()
        {
